import{_ as e,o as t,c as a}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"LinkedQL","description":"","frontmatter":{"layout":"home","title":"LinkedQL","hero":{"name":"LinkedQL","text":"Universal query engine for modern apps and agents","tagline":"LinkedQL moves applications from manual capability scaffolding to full SQL power.","actions":[{"theme":"brand","text":"Get Started","link":"/guides/"},{"theme":"alt","text":"What Is LinkedQL","link":"/overview"},{"theme":"alt","text":"Star on GitHub","link":"https://github.com/linked-db/linked-ql"}]},"features":[{"title":"Relationships, Solved","details":"Query data as objects with direct relationship traversal. LinkedQL removes the need for post-processing steps and object-relational mapping."},{"title":"Realtime, Solved","details":"Drive application state directly with live queries – without touching a subscription server or wiring reactivity. Your query becomes the subscription."},{"title":"Sync, Solved","details":"Sync data between local and remote databases in standard SQL vocabulary. With LinkedQL, the database itself becomes the sync engine."},{"title":"Runs on Your Database","details":"Run on your existing PostgreSQL or MySQL/MariaDB instance. LinkedQL integrates with your database as a query client."},{"title":"Runs Locally","details":"Embed LinkedQL as a full SQL engine locally, via FlashQL. FlashQL runs anywhere JavaScript does: server, browser, worker, edge."},{"title":"Runs Universally","details":"Query databases across runtime boundaries through a native protocol. No need for REST APIs. Simply expose the remote database for direct client-side querying."}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),i={name:"index.md"};function n(s,r,o,l,d,c){return t(),a("div")}const h=e(i,[["render",n]]);export{p as __pageData,h as default};
